import React from 'react';
import { Card, Stack, Box, Divider, Heading, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = '°C',
    forecast,
  } = props;

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="lg" 
      border={true}
      aria-label={`Weather in ${city}`}
    >
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Current Stats */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}{unit}
          </Heading>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity: {humidity}%
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind: {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((item, index) => (
            <Box
              key={index}
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            >
              <Stack align="center" gap={8}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? 'N/A'}
                </Text>
                <Text 
                  size="2xl" 
                  aria-label={`Condition: ${item.icon ?? 'N/A'}`}
                >
                  {item.icon ?? '☁️'}
                </Text>
                <Stack direction="horizontal" gap={8}>
                  <Text variant="bodySmall" weight="bold">
                    {item.high ?? 0}°
                  </Text>
                  <Text 
                    variant="bodySmall" 
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Stack, 
  Box, 
  Card, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Badge, 
  Avatar, 
  Icon 
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Task[];
  columns: Column[];
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState<Task[]>(props.tasks);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTask, setNewTask] = useState<{ title: string; priority: 'low' | 'medium' | 'high' }>({ title: '', priority: 'medium' });

  const summary = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  const handleUpdate = (action: 'move' | 'edit' | 'create', taskId: string | undefined, data: any) => {
    let updatedTasks = [...tasks];
    if (action === 'create') {
      const created = { id: Date.now().toString(), ...data };
      updatedTasks.push(created);
    } else {
      updatedTasks = updatedTasks.map((t) => (t.id === taskId ? { ...t, ...data } : t));
    }
    setTasks(updatedTasks);
    props.onTaskUpdate?.({ action, taskId, data });
  };

  const getPriorityVariant = (p?: string) => {
    if (p === 'high') return 'error';
    if (p === 'low') return 'success';
    return 'warning';
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Project Board</Heading>
            <Text variant="bodySmall">Total: {summary.total} | Completed: {summary.completed}</Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns.map((col) => (
            <Box 
              key={col.id} 
              background="var(--ggui-color-surfaceVariant)" 
              padding="var(--ggui-spacing-4)" 
              borderRadius="var(--ggui-shape-radius-lg)" 
              style={{ width: '320px', flexShrink: 0 }}
            >
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>{col.name}</Heading>
                <Stack gap="var(--ggui-spacing-3)">
                  {tasks.filter((t) => t.column === col.id).map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-4)" shadow="sm">
                      <Stack gap="var(--ggui-spacing-2)">
                        {editingId === task.id ? (
                          <Input label="Title" value={editTitle} onChange={setEditTitle} />
                        ) : (
                          <Text weight="semibold">{task.title}</Text>
                        )}
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={getPriorityVariant(task.priority)}>{task.priority}</Badge>
                          <Avatar name={task.assignee ?? 'UN'} size={24} />
                        </Stack>
                        <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                          <Select 
                            label="Move"
                            value={task.column ?? ''}
                            onChange={(v) => handleUpdate('move', task.id, { column: v })}
                            options={props.columns.map((c) => ({ value: c.id!, label: c.name! }))}
                          />
                          <Button variant="ghost" size="sm" onClick={() => {
                            if (editingId === task.id) {
                              handleUpdate('edit', task.id, { title: editTitle });
                              setEditingId(null);
                            } else {
                              setEditTitle(task.title ?? '');
                              setEditingId(task.id!);
                            }
                          }}>
                            {editingId === task.id ? 'Save' : 'Edit'}
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingTo === col.id ? (
                  <Card padding="var(--ggui-spacing-4)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input label="Task Title" value={newTask.title} onChange={(v) => setNewTask({ ...newTask, title: v })} />
                      <Select 
                        label="Priority" 
                        value={newTask.priority} 
                        onChange={(v) => setNewTask({ ...newTask, priority: v as any })} 
                        options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} 
                      />
                      <Button onClick={() => {
                        handleUpdate('create', undefined, { ...newTask, column: col.id });
                        setAddingTo(null);
                        setNewTask({ title: '', priority: 'medium' });
                      }}>Create</Button>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setAddingTo(col.id!)} leftIcon={<Icon name="plus" size={16}/>}>Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Box, Text, Stack, Divider, Input } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100)',
  'noble-gas': 'var(--ggui-color-info-100)',
  'alkali-metal': 'var(--ggui-color-warning-100)',
  'halogen': 'var(--ggui-color-error-100)',
};

export default function GeneratedComponent(props: Props) {
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const [query, setQuery] = useState('');

  const filteredElements = useMemo(() => {
    if (!query) return props.elements;
    const q = query.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(q) ||
        el.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, query]);

  const getCategoryColor = (cat?: string) => {
    if (!cat) return 'var(--ggui-color-surfaceVariant)';
    return CATEGORY_COLORS[cat] ?? 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8)">
      <Stack gap="var(--ggui-spacing-6)">
        <Input
          label="Search Elements"
          type="search"
          placeholder="Search by name or symbol..."
          value={query}
          onChange={setQuery}
        />

        <Box
          role="grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
          }}
        >
          {props.elements.map((el) => {
            const isMatch = filteredElements.includes(el);
            return (
              <div
                key={el.atomicNumber}
                role="gridcell"
                tabIndex={0}
                aria-label={`${el.name}, Symbol ${el.symbol}`}
                onKeyDown={(e) => { if (e.key === 'Enter') setSelected(el); }}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  cursor: 'pointer',
                  opacity: !query || isMatch ? 1 : 0.3,
                  transition: 'opacity 200ms ease',
                }}
                onClick={() => setSelected(el)}
              >
                <Card
                  padding="var(--ggui-spacing-1)"
                  radius="sm"
                  border={true}
                  style={{ background: getCategoryColor(el.category), height: '100%' }}
                >
                  <Stack gap={0} align="center">
                    <Text variant="caption">{el.atomicNumber ?? ''}</Text>
                    <Text variant="bodyLarge" weight="bold">{el.symbol ?? ''}</Text>
                  </Stack>
                </Card>
              </div>
            );
          })}
        </Box>

        {selected && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="bodyLarge" weight="bold">Element Details</Text>
              <Divider />
              <Text><strong>Name:</strong> {selected.name ?? 'N/A'}</Text>
              <Text><strong>Symbol:</strong> {selected.symbol ?? 'N/A'}</Text>
              <Text><strong>Atomic Number:</strong> {selected.atomicNumber ?? 'N/A'}</Text>
              <Text><strong>Atomic Weight:</strong> {selected.atomicWeight ?? 'N/A'}</Text>
              <Text><strong>Category:</strong> {selected.category ?? 'N/A'}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4)">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <Box
              key={cat}
              paddingX="var(--ggui-spacing-3)"
              paddingY="var(--ggui-spacing-1)"
              borderRadius="var(--ggui-shape-radius-sm)"
              background={color}
            >
              <Text variant="caption" style={{ textTransform: 'capitalize' }}>
                {cat.replace('-', ' ')}
              </Text>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Text, Heading, Input, Button, Badge, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function GeneratedComponent(props: Props) {
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event?.detail;
      if (detail && detail.text) {
        setMessages((prev) => [
          ...prev,
          {
            sender: detail.sender ?? 'Agent',
            text: detail.text,
            timestamp: new Date().toISOString(),
          },
        ]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = () => {
    const text = inputValue.trim();
    if (!text) return;

    const timestamp = new Date().toISOString();
    const newMessage = { sender: props.currentUser, text, timestamp };

    setMessages((prev) => [...prev, newMessage]);

    // Action Contract
    if (typeof (window as any).sendMessage === 'function') {
      (window as any).sendMessage({ text, timestamp });
    }

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <Card 
      padding={0} 
      border={true} 
      radius="lg" 
      style={{ width: '100%', height: '500px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}
    >
      <Stack 
        direction="horizontal" 
        align="center" 
        justify="between" 
        style={{ padding: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}
      >
        <Heading level={3}>{props.title}</Heading>
        {props.participantCount !== undefined && (
          <Badge variant="secondary">{props.participantCount} Participants</Badge>
        )}
      </Stack>

      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
        <div ref={scrollRef} style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4)' }} role="log" aria-label="Chat messages">
          {messages.map((msg, i) => {
            const isOwn = msg.sender === props.currentUser;
            const time = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';

            return (
              <Stack key={i} align={isOwn ? 'end' : 'start'} gap={1}>
                <Box 
                  paddingX={12} 
                  paddingY={8} 
                  borderRadius={12} 
                  background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                >
                  <Text color={isOwn ? 'white' : 'var(--ggui-color-onSurface)'} variant="body">{msg.text}</Text>
                </Box>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {msg.sender ?? 'Unknown'} • {time}
                </Text>
              </Stack>
            );
          })}
        </div>
      </Box>

      <Divider margin={0} />

      <Stack 
        direction="horizontal" 
        align="center" 
        style={{ padding: 'var(--ggui-spacing-4)', gap: 'var(--ggui-spacing-2)' }}
      >
        <Box style={{ flex: 1 }}>
          <Input 
            label="Message"
            placeholder="Type a message..." 
            value={inputValue} 
            onChange={(val) => setInputValue(val)}
            onKeyDown={handleKeyDown}
          />
        </Box>
        <Button 
          variant="primary" 
          onClick={handleSendMessage} 
          disabled={!inputValue.trim()}
          aria-label="Send Message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Box, 
  Spacer, 
  Icon 
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ 
    symbol?: string; 
    name?: string; 
    price?: number; 
    change?: number; 
    changePercent?: number 
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const handleData = (event: any) => {
      const detail = event.detail ?? {};
      if (detail.stocks) {
        setStocks(detail.stocks);
        setLastUpdated(detail.lastUpdated ?? new Date().toISOString());
        setIsLoading(false);
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
          gap: 'var(--ggui-spacing-4, 16px)' 
        }}>
          {stocks.length > 0 ? (
            stocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const isPositive = change >= 0;
              const trendColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              return (
                <Card 
                  key={`${stock.symbol ?? index}`} 
                  padding="var(--ggui-spacing-4, 16px)" 
                  shadow="sm" 
                  radius="md"
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Stack direction="horizontal" justify="between" align="start">
                      <Heading level={3}>{stock.symbol ?? '---'}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name}
                      </Text>
                    </Stack>

                    <Box aria-live="polite">
                      <Text variant="bodyLarge" size="3xl" weight="bold">
                        ${stock.price?.toFixed(2) ?? '0.00'}
                      </Text>
                    </Box>

                    <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                      <Text 
                        weight="semibold" 
                        color={trendColor} 
                        style={{ transition: 'color 200ms ease' }}
                      >
                        <Icon 
                          name={isPositive ? 'chevron-up' : 'chevron-down'} 
                          size={14} 
                          color={trendColor} 
                        />
                        {Math.abs(change).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isLoading ? 'Connecting to market feed...' : 'No market data available.'}
            </Text>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) setFormData((prev) => ({ ...prev, ...data }));
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const validateStep1 = () => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = 'Invalid email format';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    if (step < 3) setStep(step + 1);
  };

  const handleBack = () => step > 1 && setStep(step - 1);

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Profile Setup</Heading>
            <Input label="Name" value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} error={errors.name} required />
            <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} error={errors.email} required />
            <Text variant="label">Choose Avatar</Text>
            <Stack direction="horizontal" gap={8} wrap>
              {props.avatarOptions.map((emoji) => (
                <Button 
                  key={emoji} 
                  variant={formData.avatar === emoji ? 'primary' : 'secondary'} 
                  onClick={() => setFormData({ ...formData, avatar: emoji })} 
                  aria-label={`Select avatar ${emoji}`}
                  style={{ minWidth: '48px', padding: 'var(--ggui-spacing-2)' }}
                >
                  {emoji}
                </Button>
              ))}
            </Stack>
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Heading level={3}>Preferences</Heading>
            <Select 
              label="Role" 
              value={formData.role} 
              onChange={(v) => setFormData({ ...formData, role: v })} 
              options={props.roleOptions.map((r) => ({ value: r, label: r }))} 
            />
            <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
            <RadioGroup 
              label="Theme" 
              value={formData.theme} 
              onChange={(v) => setFormData({ ...formData, theme: v })} 
              options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} 
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Heading level={3}>Review</Heading>
            <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
              <Stack gap={12}>
                {Object.entries(formData).map(([k, v]) => (
                  <Stack key={k} direction="horizontal" justify="between">
                    <Text variant="label" style={{ textTransform: 'capitalize' }}>{k.replace(/([A-Z])/g, ' $1')}</Text>
                    <Text variant="body">{String(v)}</Text>
                  </Stack>
                ))}
              </Stack>
            </Box>
          </Stack>
        );
      default: return null;
    }
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={24}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Onboarding</Heading>
            <Text variant="caption" aria-current="step">Step {step} of 3</Text>
          </Stack>
          <Box background="var(--ggui-color-outlineVariant)" borderRadius={4} paddingY={4}>
            <Box background="var(--ggui-color-primary-600)" borderRadius={4} style={{ width: `${(step / 3) * 100}%`, transition: 'width 200ms ease', height: '4px' }} />
          </Box>
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>{renderStep()}</Box>
          <Divider margin={0} />
          <Stack direction="horizontal" justify="between" gap={16}>
            <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
